changeSet.sql:
ALTER TABLE monsters ADD COLUMN IF NOT EXISTS is_visible_to_players boolean NOT NULL DEFAULT false;
ALTER TABLE monsters ADD COLUMN IF NOT EXISTS is_active boolean NOT NULL DEFAULT true;
ALTER TABLE monsters ADD COLUMN IF NOT EXISTS created_by uuid NULL REFERENCES users(id);
ALTER TABLE monsters ADD COLUMN IF NOT EXISTS updated_by uuid NULL REFERENCES users(id);
ALTER TABLE monsters ADD COLUMN IF NOT EXISTS source_monster_id uuid NULL REFERENCES monsters(id) ON DELETE SET NULL;

CREATE INDEX IF NOT EXISTS idx_monsters_homebrew ON monsters (homebrew_id) WHERE homebrew_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_monsters_campaign ON monsters (campaign_id) WHERE campaign_id IS NOT NULL;
CREATE INDEX IF NOT EXISTS idx_monsters_system ON monsters (cr_value) WHERE campaign_id IS NULL AND homebrew_id IS NULL;
